('Event Manager', 'Event Manager', 'Responsible for planning, organizing, and executing events while ensuring client satisfaction and seamless experiences.', 'Dedicated event professional specializing in end-to-end event planning and execution, ensuring every client receives exceptional service and unforgettable experiences.', 4, true),
('Project Manager', 'Project Manager', 'Leads individual event projects, manages budgets, timelines, and coordinates on-site operations.', 'Detail-oriented project leader who manages event budgets, coordinates timelines, and oversees on-site operations to ensure flawless event delivery within scope and budget.', 5, true),
('Creative Director', 'Creative Director', 'Heads the design and branding team, developing innovative concepts for décor, stalls, and visual identity.', 'Artistic visionary leading the creative team in developing innovative design concepts, branding strategies, and visual identities that bring client visions to life.', 6, true),
('Technical Head', 'Technical Head (AV & Infrastructure)', 'Oversees audio-visual, lighting, air-conditioning, and technical solutions for all events.', 'Technical expert managing all audio-visual systems, lighting solutions, infrastructure setups, and innovative technical solutions that power world-class events.', 7, true),
('Site Manager', 'Site Managers', 'On-ground leaders who supervise setup, safety, and vendor coordination during events.', 'Field leaders responsible for on-site event execution, safety protocols, vendor coordination, and ensuring all technical and logistical elements work seamlessly.', 8, true),
('Logistics Manager', 'Logistics & Warehouse Manager', 'Handles transportation, storage, and inventory of event structures, ACs, stalls, and décor.', 'Operations specialist managing transportation logistics, warehouse operations, and inventory of premium event equipment including structures, ACs, and décor elements.', 9, true),
('Client Relations Manager', 'Client Relations Manager', 'Main point of contact for clients, ensuring clear communication and satisfaction throughout the project.', 'Client-focused professional serving as the primary liaison between clients and internal teams, ensuring clear communication and exceptional satisfaction throughout every project.', 10, true),
('Business Development Executive', 'Business Development Executives', 'Expand client base, manage partnerships, and bring in new business opportunities.', 'Growth-oriented professionals focused on expanding the client base, developing strategic partnerships, and identifying new business opportunities in the event management sector.', 11, true);

