('Portable Dome / Luxury Lounges', 'VIP-ready lounges with premium finishes for dignitaries and corporate guests. Elegant and comfortable spaces for high-profile attendees.', 'VIP luxury lounges for dignitaries and guests', 'Premium Pricing', ARRAY['Specialized Rentals', 'VIP Lounges'], ARRAY[]::text[], 'luxury lounge VIP portable dome dignitary', true, true, 14),

('Portable AC Lounges / Green Rooms', 'Climate-controlled green rooms and lounges for artists, VIPs, and leadership teams. Comfortable retreat spaces with temperature control.', 'Climate-controlled green rooms and VIP areas', 'Premium Pricing', ARRAY['Specialized Rentals', 'Green Rooms'], ARRAY[]::text[], 'AC lounge green room VIP climate control', true, true, 15),

('Custom Stage Platforms (Mega-Scale)', 'Engineered staging systems for large crowds, award shows, and cultural events. Professional platforms designed for spectacular performances.', 'Large-scale custom stage platforms for events', 'Premium Pricing', ARRAY['Specialized Rentals', 'Staging'], ARRAY[]::text[], 'custom stage platform mega scale performance', true, true, 16);